// ── Download dropdown toggle ──
// Simple toggle for the unified download dropdown in the nav header.
// ZIP files are static (generated by generate-zips.js), so no client-side work needed.

(function () {
  'use strict';

  window.toggleDownloadDropdown = function (e) {
    e.stopPropagation();
    var dd = document.getElementById('global-download-dropdown');
    if (!dd) return;
    dd.classList.toggle('hidden');
    if (!dd.classList.contains('hidden')) {
      setTimeout(function () {
        document.addEventListener('click', function handler() {
          dd.classList.add('hidden');
          document.removeEventListener('click', handler);
        }, { once: true });
      }, 0);
    }
  };
})();
